// ─── Constants & Config ───────────────────────────────────────────────────────
const MONTHS = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
const ACTUALS_THRU = 4; // Jan–May (index 0–4) are actual; index 5+ are projections
const YEARS = [2026, 2027, 2028];

// ─── Utility Helpers ──────────────────────────────────────────────────────────
const fmt = (n, compact = false) => {
  if (n == null || isNaN(n)) return "—";
  const abs = Math.abs(n);
  if (compact && abs >= 1_000_000) return `${n < 0 ? "-" : ""}$${(abs/1_000_000).toFixed(1)}M`;
  if (compact && abs >= 1_000) return `${n < 0 ? "-" : ""}$${(abs/1_000).toFixed(0)}K`;
  return new Intl.NumberFormat("en-US", { style: "currency", currency: "USD", maximumFractionDigits: 0 }).format(n);
};
const pct = (n) => n == null ? "—" : `${(n * 100).toFixed(1)}%`;
const varColor = (v) => v > 0 ? "#22c55e" : v < 0 ? "#ef4444" : "#94a3b8";
const sum = (arr) => arr ? arr.reduce((a, b) => a + (b || 0), 0) : 0;
const isActualMonth = (yr, mi) => yr === 2026 && mi <= ACTUALS_THRU;
const getRowData = (row, year) => year === 2026 ? row.v26 : year === 2027 ? row.v27 : row.v28;
const isTotal = (a) => a.startsWith("Total ") || a === "Gross Profit" || a === "Net Income" || a === "Net Operating Income" || a === "Total Other Expenses";
const isHeader = (a) => ["Income","Cost of Goods Sold","Expenses","Other Expenses","Net Other Income"].includes(a) || a.startsWith("Check");
const displayLabel = (a) => a === "Other Expenses" ? "Depreciation & Amortization" : a;

// ─── FCA Logo ─────────────────────────────────────────────────────────────────
const FCALogo = ({ size = 36 }) => (
  <svg width={size} height={size} viewBox="0 0 100 100" fill="none">
    <circle cx="50" cy="50" r="48" stroke="white" strokeWidth="4"/>
    <circle cx="50" cy="30" r="8" fill="white"/>
    <path d="M 10 70 Q 50 20 90 55" stroke="white" strokeWidth="4" fill="none" strokeLinecap="round"/>
    <text x="50" y="88" textAnchor="middle" fill="white" fontSize="22" fontWeight="bold" fontFamily="sans-serif">FCA</text>
  </svg>
);

// ─── KPI Summary from monthly data ───────────────────────────────────────────
const getAnnualKPIs = (year) => {
  const k = KPIS_ALL[String(year)];
  if (!k) return {};
  return {
    revenue: sum(k.rev),
    cogs: sum(k.cogs),
    grossProfit: sum(k.gp),
    expenses: sum(k.exp),
    netIncome: sum(k.ni),
    ebitda: sum(k.ebitda),
    gpMargin: sum(k.rev) ? sum(k.gp) / sum(k.rev) : 0,
    niMargin: sum(k.rev) ? sum(k.ni) / sum(k.rev) : 0,
  };
};

// ─── Build monthly chart data for a year ─────────────────────────────────────
const getMonthlyChart = (year) => {
  const k = KPIS_ALL[String(year)];
  if (!k) return [];
  return MONTHS.map((m, i) => ({
    month: m,
    Revenue: k.rev[i] || 0,
    "Gross Profit": k.gp[i] || 0,
    Expenses: k.exp[i] || 0,
    "Net Income": k.ni[i] || 0,
    isActual: isActualMonth(year, i),
  }));
};

